 17→class BackgroundCheckService
 18→{
 19→    /**
 20→     * 获取背调记录列表，按工作经历段分组，每条经历内按创建时间倒序.
 21→     * 动态检测 pending 超 1 个月改为 expired，并附加 last_update_time.
 22→     */
 23→    public function getList(int $recProId): array
 24→    {
 25→        $records = BackgroundCheckRecordMd::where('rec_pro_id', $recProId)
 26→            ->orderBy('work_experience_index')
 27→            ->orderBy('created_at', 'desc')
 28→            ->get()
 29→            ->toArray();
 30→
 31→        foreach ($records as &$r) {
 32→            if ($r['status'] === BackgroundCheckRecordMd::STATUS_PENDING && !empty($r['sent_at'])) {
 33→                $sentAt = strtotime($r['sent_at']);
 34→                if ($sentAt && (time() - $sentAt) > 30 * 86400) {
 35→                    BackgroundCheckRecordMd::where('id', $r['id'])->update(['status' => BackgroundCheckRecordMd::STATUS_EXPIRED]);
 36→                    $r['status'] = BackgroundCheckRecordMd::STATUS_EXPIRED;
 37→                }
 38→            }
 39→            $r['last_update_time'] = ($r['status'] === BackgroundCheckRecordMd::STATUS_FEEDBACK && !empty($r['feedback_at']))
 40→                ? $r['feedback_at']
 41→                : ($r['sent_at'] ?? $r['created_at'] ?? '');
 42→        }
 43→        unset($r);
 44→
 45→        $grouped = [];
 46→        foreach ($records as $r) {
 47→            $key = (int)$r['work_experience_index'];
 48→            if (!isset($grouped[$key])) {
 49→                $grouped[$key] = [];
 50→            }
 51→            $grouped[$key][] = $r;
 52→        }
 53→        return ['list' => $grouped, 'data' => $records];
 54→    }
 55→
 56→    /**
 57→     * 发起背调邮件.
 58→     */
 59→    public function send(array $input): array
 60→    {
 61→        $recProId = (int)$input['rec_pro_id'];
 62→        $rec = RecruitmentProcessionMd::find($recProId);
 63→        if (!$rec) {
 64→            throw new \App\Exceptions\UserException(__('my_api.recruitment_procession_not_exist'), \App\Exceptions\ExceptionCode::USER_INVALID_INPUT);
 65→        }
 66→        $resume = ResumeMd::with('GetResumeExperience')->find($rec->resume_id);
 67→        if (!$resume) {
 68→            throw new \App\Exceptions\UserException(__('my_api.resume_not_exist'), \App\Exceptions\ExceptionCode::USER_INVALID_INPUT);
 69→        }
 70→
 71→        $workIndex = (int)Arr::get($input, 'work_experience_index', 1);
 72→        if ($workIndex < 1 || $workIndex > 3) {
 73→            throw new \App\Exceptions\UserException(__('my_api.invalid_work_experience_index'), \App\Exceptions\ExceptionCode::USER_INVALID_INPUT);
 74→        }
 75→
 76→        // 校验录用材料中必须有背调授权书
 77→        $attachFile = $this->getBackgroundCheckAuthFile($resume->id);
 78→        if (!$attachFile) {
 79→            throw new \App\Exceptions\UserException(__('my_api.background_check_auth_file_required'), \App\Exceptions\ExceptionCode::USER_INVALID_INPUT);
 80→        }
 81→
 82→        $experiences = ($resume->get_resume_experience ?? collect())->toArray();
 83→        $workExp = $this->getWorkExperienceByIndex($experiences, $workIndex);
 84→        if (!$workExp) {
 85→            $company = trim(Arr::get($input, 'company', ''));
 86→            $position = trim(Arr::get($input, 'position', ''));
 87→            $startDate = trim(Arr::get($input, 'start_date', ''));
 88→            $endDate = trim(Arr::get($input, 'end_date', ''));
 89→            if ($company === '' || $position === '' || $startDate === '' || $endDate === '') {
 90→                throw new \App\Exceptions\UserException(__('my_api.work_experience_not_found'), \App\Exceptions\ExceptionCode::USER_INVALID_INPUT);
 91→            }
 92→            $workExp = [
 93→                'name' => $company,
 94→                'company_name' => $company,
 95→                'position' => $position,
 96→                'description' => $position,
 97→                'start_time' => $startDate,
 98→                'end_time' => $endDate,
 99→            ];
100→        }
101→
102→        $record = BackgroundCheckRecordMd::create([
103→            'rec_pro_id' => $recProId,
104→            'resume_id' => $resume->id,
105→            'work_experience_index' => $workIndex,
106→            'company' => Arr::get($input, 'company', $workExp['name'] ?? $workExp['company_name'] ?? ''),
107→            'position' => Arr::get($input, 'position', $this->getWorkExpPositionDefault($workExp)),
108→            'work_location' => Arr::get($input, 'work_location', ''),
109→            'employment_type' => Arr::get($input, 'employment_type', ''),
110→            'start_date' => Arr::get($input, 'start_date', $workExp['start_time'] ?? ''),
111→            'end_date' => Arr::get($input, 'end_date', $workExp['end_time'] ?? ''),
112→            'salary_structure' => Arr::get($input, 'salary_structure', ''),
113→            'departure_type' => Arr::get($input, 'departure_type', ''),
114→            'has_compensation' => Arr::get($input, 'has_compensation', ''),
115→            'background_check_email' => Arr::get($input, 'background_check_email', ''),
116→            'email_search' => Arr::get($input, 'email_search', Arr::get($input, 'background_check_email', '')),
117→            'status' => BackgroundCheckRecordMd::STATUS_PENDING,
118→            'email_subject' => Arr::get($input, 'email_subject', ''),
119→            'email_content' => Arr::get($input, 'email_content', ''),
120→            'sent_at' => now(),
121→        ]);
122→
123→        $hrNickname = AuthRecord::user()->nickname ?? '';
124→        app(BackgroundCheckQueryService::class)->syncFromRecord($record, null, $hrNickname);
125→
126→        return ['id' => $record->id, 'success' => true];
127→    }
