129→    /**
130→     * 更新背调记录的邮件内容（用于发送前写入带 token 的 feedbackUrl）.
131→     */
132→    public function updateEmailContent(int $backgroundCheckId, string $emailSubject, string $emailContent): array
133→    {
134→        $record = BackgroundCheckRecordMd::find($backgroundCheckId);
135→        if (!$record) {
136→            throw new \App\Exceptions\UserException(__('my_api.background_check_record_not_found'), \App\Exceptions\ExceptionCode::USER_INVALID_INPUT);
137→        }
138→        $record->update(['email_subject' => $emailSubject, 'email_content' => $emailContent]);
139→        return ['id' => $record->id, 'success' => true];
140→    }
