142→    /**
143→     * 生成背调反馈链接 token，供 background.html 使用（参考应聘登记 candidate.html）.
144→     * info 包含完整配置供 get-config 使用，避免 official-chn 回调 hr.
145→     */
146→    public function generateToken(int $backgroundCheckId, string $idSign = '', string $dataInfo = ''): array
147→    {
148→        $record = BackgroundCheckRecordMd::find($backgroundCheckId);
149→        if (!$record) {
150→            throw new \App\Exceptions\UserException(__('my_api.background_check_record_not_found'), \App\Exceptions\ExceptionCode::USER_INVALID_INPUT);
151→        }
152→
153→        $token = $idSign ?: Str::random(32);
154→        $expireDays = 90;
155→        setAuthorityToken($token, [$backgroundCheckId], ['anonymous'], $expireDays * 86400, 'background_check');
156→
157→        if ($dataInfo) {
158→            $info = $dataInfo;
159→        } else {
160→            $resume = $record->resume;
161→            $candidateName = $resume ? ($resume->username ?? $resume->nickname ?? '') : '';
162→            $identification = $resume ? ($resume->identification ?? '') : '';
163→            $info = my_json_encode([
164→                'background_check_id' => $backgroundCheckId,
165→                'rec_pro_id' => $record->rec_pro_id,
166→                'resume_id' => $record->resume_id,
167→                'candidate_name' => $candidateName,
168→                'identification' => $identification,
169→                'company' => $record->company ?? '',
170→                'work_location' => $record->work_location ?? '',
171→                'employment_type' => $record->employment_type ?? '',
172→                'start_date' => $record->start_date ?? '',
173→                'end_date' => $record->end_date ?? '',
174→                'position' => $record->position ?? '',
175→                'salary_structure' => $record->salary_structure ?? '',
176→                'departure_type' => $record->departure_type ?? '',
177→                'has_compensation' => $record->has_compensation ?? '',
178→            ]);
179→        }
180→
181→        OfficialApiLib::sendRequest('official-api/common/record-id-sign', [
182→            'id_sign' => $token,
183→            'type' => 'background_check',
184→            'info' => $info,
185→        ]);
186→        return ['token' => $token];
187→    }
