230→    /**
231→     * 根据背调记录 ID 获取背调授权书附件信息（供 mail/send 使用，避免前端传加密 path）.
232→     */
233→    public function getBackgroundCheckAuthFileForMail(int $backgroundCheckId): ?array
234→    {
235→        Log::info('[背调附件] getBackgroundCheckAuthFileForMail background_check_id='.$backgroundCheckId);
236→        $record = BackgroundCheckRecordMd::find($backgroundCheckId);
237→        if (!$record) {
238→            Log::warning('[背调附件] 背调记录不存在 background_check_id='.$backgroundCheckId);
239→            return null;
240→        }
241→        Log::info('[背调附件] 背调记录 resume_id='.$record->resume_id);
242→        return $this->getBackgroundCheckAuthFile($record->resume_id);
243→    }
