245→    /**
246→     * 根据背调记录 ID 和前端选中的附件索引，获取对应的单个背调授权书附件.
247→     */
248→    public function getBackgroundCheckAuthFileByIndex(int $backgroundCheckId, ?int $attachIndex = null): ?array
249→    {
250→        $record = BackgroundCheckRecordMd::find($backgroundCheckId);
251→        if (!$record) {
252→            return null;
253→        }
254→        $allFiles = $this->getAllBackgroundCheckAuthFiles($record->resume_id);
255→        if (empty($allFiles)) {
256→            return null;
257→        }
258→        if ($attachIndex !== null && isset($allFiles[$attachIndex])) {
259→            return $allFiles[$attachIndex];
260→        }
261→        return $allFiles[0] ?? null;
262→    }
