264→    /**
265→     * 获取所有背调授权书文件（type=backgroundCheck）.
266→     *
267→     * @return array[] 每项包含 disk, file_store_path, file_real_name
268→     */
269→    private function getAllBackgroundCheckAuthFiles(int $resumeId): array
270→    {
271→        $or = OnboardingReviewMd::where('resume_id', $resumeId)->orderBy('id', 'desc')->first();
272→        if (!$or) {
273→            return [];
274→        }
275→        $files = FileStorePathMd::where('table_name', 'onboarding_review')
276→            ->where('table_id', $or->id)
277→            ->where('type', 'backgroundCheck')
278→            ->where('is_on', 1)
279→            ->get();
280→        $result = [];
281→        foreach ($files as $file) {
282→            $result[] = [
283→                'disk' => $file->disk ?: 'onboarding_review',
284→                'file_store_path' => $file->file_store_path,
285→                'file_real_name' => $file->file_real_name ?? '',
286→            ];
287→        }
288→        return $result;
289→    }
290→
291→    private function getWorkExperienceByIndex(array $experiences, int $index): ?array
292→    {
293→        $workList = array_values(array_filter((array)$experiences, function ($e) {
294→            $e = is_array($e) ? $e : (array)$e;
295→            return strtolower(trim($e['type'] ?? '')) === 'work';
296→        }));
297→        if (empty($workList) || $index < 1 || $index > count($workList)) {
298→            return null;
299→        }
300→        usort($workList, function ($a, $b) {
301→            $a = is_array($a) ? $a : (array)$a;
302→            $b = is_array($b) ? $b : (array)$b;
303→            $endA = strtotime($a['end_time'] ?? $a['start_time'] ?? '0');
304→            $endB = strtotime($b['end_time'] ?? $b['start_time'] ?? '0');
305→            return $endB <=> $endA;
306→        });
307→        return $workList[$index - 1] ?? null;
308→    }
309→
310→    /**
311→     * 从录用材料中获取背调授权书文件（type=backgroundCheck）.
312→     * @return null|array{disk: string, file_store_path: string, file_real_name: string}
313→     */
314→    private function getBackgroundCheckAuthFile(int $resumeId): ?array
315→    {
316→        Log::info('[背调附件] getBackgroundCheckAuthFile resume_id='.$resumeId);
317→        $or = OnboardingReviewMd::where('resume_id', $resumeId)->orderBy('id', 'desc')->first();
318→        if (!$or) {
319→            Log::warning('[背调附件] 未找到 onboarding_review resume_id='.$resumeId);
320→            return null;
321→        }
322→        Log::info('[背调附件] onboarding_review id='.$or->id);
323→        $file = FileStorePathMd::where('table_name', 'onboarding_review')
324→            ->where('table_id', $or->id)
325→            ->where('type', 'backgroundCheck')
326→            ->where('is_on', 1)
327→            ->first();
328→        if (!$file) {
329→            Log::warning('[背调附件] 未找到 type=backgroundCheck 文件 table_id='.$or->id);
330→            return null;
331→        }
332→        Log::info('[背调附件] FileStorePath id='.$file->id.', disk='.$file->disk.', file_store_path='.$file->file_store_path);
333→        return [
334→            'disk' => $file->disk ?: 'onboarding_review',
335→            'file_store_path' => $file->file_store_path,
336→            'file_real_name' => $file->file_real_name ?? '',
337→        ];
338→    }
339→
340→    private function getWorkExpPositionDefault(array $workExp): string
341→    {
342→        if (!empty($workExp['position'])) {
343→            return $workExp['position'];
344→        }
345→        $desc = $workExp['description'] ?? '';
346→        if ($desc) {
347→            $parts = explode(' | ', $desc);
348→            return $parts[0] ?? '';
349→        }
350→        return '';
351→    }
352→}
