import axios from 'axios'

import { ajaxUrl } from '@/appConstant'
import { uploadDict } from '@/common/MDictionary'
import store from '@/store'
import { axiosPostWithInt } from '@/store'
import { getUrlParamByName } from '@/utils'
import commonRequestApis from '@apis/CommonApis/CommonApis'

function SectionToChinese(section) {
    const chnNumChar = ['零', '一', '二', '三', '四', '五', '六', '七', '八', '九']
    const chnUnitChar = ['', '十', '百', '千', '万', '亿', '万亿', '亿亿']
    let strIns = '',
        chnStr = ''
    let unitPos = 0
    let zero = true
    while (section > 0) {
        const v = section % 10
        if (v === 0) {
            if (!zero) {
                zero = true
                chnStr = chnNumChar[v] + chnStr
            }
        } else {
            zero = false
            strIns = chnNumChar[v]
            strIns += chnUnitChar[unitPos]
            chnStr = strIns + chnStr
        }
        unitPos += 1
        section = Math.floor(section / 10)
    }
    return chnStr
}
export const fileCache = new (class {
    fileMap = new Map()
    getFile(
        uniqueNameEncrypt: string,
        disk: string,
        fileExtension?: string,
    ): Promise<{
        content: string
        fileType: string
    }> {
        const key = `${uniqueNameEncrypt}_${disk}`
        return new Promise((resolve, reject) => {
            if (this.fileMap.has(key)) {
                resolve(this.fileMap.get(key)!)
                return
            }
            const ext = (fileExtension || '').toLowerCase()
            if (ext === 'xlsx' || ext === 'xls') {
                this.getFileViaDownloadThenExcelPdf(uniqueNameEncrypt, disk, key, ext, resolve, reject)
                return
            }
            if (ext === 'doc' || ext === 'docx') {
                this.getFileViaDownloadThenWordPdf(uniqueNameEncrypt, disk, key, ext, resolve, reject)
                return
            }
            commonRequestApis
                .previewPdf(
                    {
                        file_name: uniqueNameEncrypt,
                        disk: disk || 'course',
                        sys_site: store?.state?.userInfo?.sysSite || getUrlParamByName('sys_site'),
                    },
                    false,
                )
                .then(r => {
                    const target = {
                        fileType: r.file_extention,
                        content: r.file_extention === 'pdf' ? atob(r.file_content) : `data:image/${r.file_extention};base64, ${r.file_content}`,
                    }
                    this.fileMap.set(key, target)
                    resolve(target)
                })
                .catch(e => {
                    console.error('fileCache getFile error', e)
                    reject(e)
                })
        })
    }

    private async getFileViaDownloadThenExcelPdf(
        uniqueNameEncrypt: string,
        disk: string,
        key: string,
        ext: string,
        resolve: (v: { content: string, fileType: string }) => void,
        reject: (e: any) => void,
    ) {
        try {
            const sysSite = store?.state?.userInfo?.sysSite || getUrlParamByName('sys_site')
            const downloadUrl = `${ajaxUrl.WEB_API_URL}tool/download?file_name=${encodeURIComponent(uniqueNameEncrypt)}&disk=${encodeURIComponent(disk || 'course')}&sys_site=${encodeURIComponent(sysSite || '')}`
            const response = await axios.get(downloadUrl, { responseType: 'arraybuffer', withCredentials: true })
            const blob = new Blob([response.data], {
                type: ext === 'xlsx' ? 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' : 'application/vnd.ms-excel',
            })
            const file = new File([blob], `temp.${ext}`, { type: blob.type })
            const uploadRes = await uploadDict.uploadFileAPI(file, () => {}, 'comm', 'workflow')
            const publicUrl = uploadRes.src
            const transcodeResponse: any = await axiosPostWithInt(ajaxUrl.WEB_API_URL + 'invoice/excel-pdf', {
                url: publicUrl,
                intact_columns: ['url'],
            })
            const pdfContent
                = transcodeResponse?.data?.content ?? transcodeResponse?.content ?? transcodeResponse?.data?.data?.content
            if (!pdfContent) {
                reject(new Error('excel 转 pdf 失败'))
                return
            }
            const target = { fileType: 'pdf', content: atob(pdfContent) }
            this.fileMap.set(key, target)
            resolve(target)
        } catch (e) {
            console.error('fileCache getFile xlsx->pdf error', e)
            reject(e)
        }
    }

    private async getFileViaDownloadThenWordPdf(
        uniqueNameEncrypt: string,
        disk: string,
        key: string,
        ext: string,
        resolve: (v: { content: string; fileType: string }) => void,
        reject: (e: any) => void,
    ) {
        try {
            const sysSite = store?.state?.userInfo?.sysSite || getUrlParamByName('sys_site')
            const downloadUrl = `${ajaxUrl.WEB_API_URL}tool/download?file_name=${encodeURIComponent(uniqueNameEncrypt)}&disk=${encodeURIComponent(disk || 'course')}&sys_site=${encodeURIComponent(sysSite || '')}`
            const response = await axios.get(downloadUrl, { responseType: 'arraybuffer', withCredentials: true })
            const blob = new Blob([response.data], {
                type: ext === 'docx' ? 'application/vnd.openxmlformats-officedocument.wordprocessingml.document' : 'application/msword',
            })
            const file = new File([blob], `temp.${ext}`, { type: blob.type })
            const uploadRes = await uploadDict.uploadFileAPI(file, () => {}, 'comm', 'workflow')
            const publicUrl = uploadRes.src
            const transcodeResponse: any = await axiosPostWithInt(ajaxUrl.WEB_API_URL + 'invoice/word-pdf', {
                url: publicUrl,
                intact_columns: ['url'],
            })
            const pdfContent =
                transcodeResponse?.data?.content ?? transcodeResponse?.content ?? transcodeResponse?.data?.data?.content
            if (!pdfContent) {
                reject(new Error('word 转 pdf 失败'))
                return
            }
            const target = { fileType: 'pdf', content: atob(pdfContent) }
            this.fileMap.set(key, target)
            resolve(target)
        } catch (e) {
            console.error('fileCache getFile word->pdf error', e)
            reject(e)
        }
    }
})()
