async handlePreviewAttach(file: any) {
    const fileNameEncrypt = file.file_name_encrypt ?? file.file_store_path
    if (!fileNameEncrypt) return
    const storePath = file.file_store_path || fileNameEncrypt
    const displayName = file.file_real_name || this.getRealFileName(storePath) || '背调授权书.pdf'
    const fileTypeReg = /\.pdf$|\.png$|\.jpe?g$/i
    if (!fileTypeReg.test(storePath)) {
        // 不可预览的格式，直接下载
        this.handleDownloadAttach(file)
        return
    }
    this.previewDia = { visible: true, loading: true, fileName: displayName, uniqueName: storePath, fileType: '', content: '' }
    try {
        const ext = storePath.includes('.') ? storePath.split('.').pop()!.toLowerCase() : ''
        const result = await fileCache.getFile(fileNameEncrypt, file.disk || 'onboarding_review', ext)
        this.previewDia.fileType = result.fileType
        this.previewDia.content = result.content
    } catch (e) {
        console.error('[背调附件预览] 加载失败', e)
        this.$message.warning('预览加载失败，请尝试下载查看')
    } finally {
        this.previewDia.loading = false
    }
}

loadPdfMethod(src: string) {
    return Promise.resolve(this.previewDia.content)
}

