public function PreviewPublicFile(Request $request)
{
    $disk = Storage::disk($request->disk ?? 'course');
    $lastDotPos = strrpos($request->file_name, '.');
    if ($lastDotPos === false) {
        return $this->responseJsonFail(__('my_api.file_no_ext', ['fileName' => $request->file_name]), UserException::ERR_USER_OPERATE_LIMIT);
    }
    $ext = substr($request->file_name, $lastDotPos + 1);
    // 可直接预览的文件，直接返回文件内容
    if (in_array(strtolower($ext), ['pdf', 'jpg', 'png', 'jpeg', 'bmp', 'psd'])) {
        return $this->responseJsonSuccess([
            'file_content' => base64_encode($disk->get($request->file_name)),
            'file_extention' => $ext,
        ]);
    }
    // 不可直接预览的文件
    $tempName = md5($request->file_name);
    $disk->copy($request->file_name, $tempName);
    $pdfName = convertToOtherType($disk->path($tempName));

    // php进程结束时，删除临时文件
    register_shutdown_function(function () use ($disk, $tempName, $pdfName) {
        $disk->delete($tempName);
        $disk->delete($pdfName);
    });

    return $this->responseJsonSuccess([
        'file_content' => base64_encode($disk->get($pdfName)),
        'file_extention' => 'pdf',
    ]);
}

/**
 * 查出所有的花名和合同初签时间.
