 */
public function getStaffContractDate()
{
    $data = StaffContractMd::alias('sc')->join('staff_information as si', 'si.id', '=', 'sc.staff_id')
        // ->where('contract_number', '=', 1)
        ->selectRaw('nickname, min(start_time) as start_time')
        ->get()->toArray();

